<?php
namespace Tests\Feature\Hr;use Illuminate\Support\Facades\Artisan;use Illuminate\Support\Facades\Schema;use Tests\TestCase;
class HrPhase5BLifecycleRollbackTest extends TestCase{use RefreshHrDatabase;public function test_lifecycle_schema_exists():void{$this->assertTrue(Schema::hasTable('hr_onboarding_checklists'));$this->assertTrue(Schema::hasColumns('hr_onboarding_tasks',['template_key','due_on','evidence']));$this->assertTrue(Schema::hasTable('hr_offboarding_checklists'));$this->assertTrue(Schema::hasColumns('hr_offboarding_tasks',['is_required','completed_by']));}public function test_rollback_preserves_recruitment():void{Artisan::call('migrate:rollback', ['--step' => 1]);Artisan::call('migrate:rollback', ['--step' => 1]);Artisan::call('migrate:rollback', ['--step' => 1]);Artisan::call('migrate:rollback', ['--step' => 1]);Artisan::call('migrate:rollback',['--step' => 4]);Artisan::call('migrate:rollback', ['--step' => 1]);Artisan::call('migrate:rollback',['--step'=>4]);Artisan::call('migrate:rollback',['--step'=>4]);$this->assertFalse(Schema::hasTable('hr_onboarding_checklists'));$this->assertTrue(Schema::hasTable('hr_job_postings'));$this->assertTrue(Schema::hasTable('hr_surveys'));}}
